  public class ContourSpec {
    public bool Direction;
    public double[,] Points;
    public ContourSpec(bool direction, double[,] points) { Direction = direction; Points = points; }
  }

  static AreaProfile MakeProfile(Document doc, string name, ContourSpec[] contours) {
    Area area = new Area(doc);
    foreach (ContourSpec contour in contours) AddClosedPolylineContour(doc, area, contour);
    StandardWorkplane top = new StandardWorkplane(doc, StandardWorkplane.StandardType.Top);
    AreaProfile profile = new AreaProfile(doc);
    profile.Name = name;
    profile.Area = area;
    profile.WorkSurface = top;
    profile.VisibleInScene = false;
    return profile;
  }

  static void AddClosedPolylineContour(Document doc, Area area, ContourSpec contour) {
    List<Point> points = new List<Point>();
    int count = contour.Points.GetLength(0);
    for (int i = 0; i < count; i++) points.Add(new Point(contour.Points[i,0], contour.Points[i,1]));
    if (points.Count == 0) throw new InvalidOperationException("Empty contour");
    Point first = points[0];
    Point last = points[points.Count - 1];
    if (Math.Abs(first.X - last.X) > 1e-9 || Math.Abs(first.Y - last.Y) > 1e-9) points.Add(new Point(first.X, first.Y));
    PolylineOutline outline = new PolylineOutline(doc, new PolylineGeometry(points));
    outline.IsService = true;
    TFlex.Model.Model2D.Contour areaContour = area.AppendContour();
    OutlineContourSegment segment = new OutlineContourSegment(areaContour);
    segment.Outline = outline;
    segment.Direction = contour.Direction;
  }
